import{_ as i,c as e,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Расширенные функции: управление несколькими аккаунтами | Antigravity Auth","description":"Освойте расширенные возможности плагина Antigravity Auth. Углубленное изучение балансировки нагрузки между аккаунтами, интеллектуального выбора аккаунтов, обработки ограничений скорости, восстановления сессий и преобразования запросов.","frontmatter":{"title":"Расширенные функции: управление несколькими аккаунтами | Antigravity Auth","sidebarTitle":"Работа с несколькими аккаунтами","subtitle":"Расширенные функции: управление несколькими аккаунтами","description":"Освойте расширенные возможности плагина Antigravity Auth. Углубленное изучение балансировки нагрузки между аккаунтами, интеллектуального выбора аккаунтов, обработки ограничений скорости, восстановления сессий и преобразования запросов.","order":3},"headers":[],"relativePath":"ru/NoeFabris/opencode-antigravity-auth/advanced/index.md","filePath":"ru/NoeFabris/opencode-antigravity-auth/advanced/index.md"}'),r={name:"ru/NoeFabris/opencode-antigravity-auth/advanced/index.md"};function o(n,a,h,u,s,d){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="расширенные-функции" tabindex="-1">Расширенные функции <a class="header-anchor" href="#расширенные-функции" aria-label="Permalink to &quot;Расширенные функции&quot;">​</a></h1><p>Эта глава поможет вам углубленно освоить расширенные возможности плагина Antigravity Auth, включая балансировку нагрузки между несколькими аккаунтами, интеллектуальный выбор аккаунтов, обработку ограничений скорости, восстановление сессий, преобразование запросов и другие ключевые механизмы. Независимо от того, оптимизируете ли вы использование квот или разбираетесь со сложными проблемами, здесь вы найдете все необходимые ответы.</p><h2 id="предварительные-условия" tabindex="-1">Предварительные условия <a class="header-anchor" href="#предварительные-условия" aria-label="Permalink to &quot;Предварительные условия&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Перед началом убедитесь, что</p><ul><li>✅ Завершили <a href="./../start/quick-install/">Быструю установку</a> и успешно добавили первый аккаунт</li><li>✅ Завершили <a href="./../start/first-auth-login/">Первую аутентификацию</a> и понимаете процесс OAuth</li><li>✅ Завершили <a href="./../start/first-request/">Первый запрос</a> и проверили, что плагин работает корректно</li></ul></div><h2 id="путь-обучения" tabindex="-1">Путь обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь обучения&quot;">​</a></h2><h3 id="_1-настроика-нескольких-аккаунтов" tabindex="-1">1. <a href="./multi-account-setup/">Настройка нескольких аккаунтов</a> <a class="header-anchor" href="#_1-настроика-нескольких-аккаунтов" aria-label="Permalink to &quot;1. [Настройка нескольких аккаунтов](./multi-account-setup/)&quot;">​</a></h3><p>Настройте несколько аккаунтов Google для объединения квот и балансировки нагрузки.</p><ul><li>Добавьте несколько аккаунтов для увеличения общего лимита квот</li><li>Поймите двойную систему квот (Antigravity + Gemini CLI)</li><li>Выберите подходящее количество аккаунтов в зависимости от сценария использования</li></ul><h3 id="_2-стратегии-выбора-аккаунтов" tabindex="-1">2. <a href="./account-selection-strategies/">Стратегии выбора аккаунтов</a> <a class="header-anchor" href="#_2-стратегии-выбора-аккаунтов" aria-label="Permalink to &quot;2. [Стратегии выбора аккаунтов](./account-selection-strategies/)&quot;">​</a></h3><p>Освойте лучшие практики использования трех стратегий выбора аккаунтов: sticky, round-robin и hybrid.</p><ul><li>1 аккаунт → стратегия sticky для сохранения кэша промптов</li><li>2-3 аккаунта → стратегия hybrid для интеллектуального распределения запросов</li><li>4+ аккаунтов → стратегия round-robin для максимальной пропускной способности</li></ul><h3 id="_3-обработка-ограничении-скорости" tabindex="-1">3. <a href="./rate-limit-handling/">Обработка ограничений скорости</a> <a class="header-anchor" href="#_3-обработка-ограничении-скорости" aria-label="Permalink to &quot;3. [Обработка ограничений скорости](./rate-limit-handling/)&quot;">​</a></h3><p>Поймите механизмы обнаружения ограничений скорости, автоматических повторных попыток и переключения аккаунтов.</p><ul><li>Различайте 5 различных типов ошибок 429</li><li>Поймите алгоритм экспоненциального отката при автоматических повторных попытках</li><li>Освойте логику автоматического переключения аккаунтов в сценариях с несколькими аккаунтами</li></ul><h3 id="_4-восстановление-сессии" tabindex="-1">4. <a href="./session-recovery/">Восстановление сессий</a> <a class="header-anchor" href="#_4-восстановление-сессии" aria-label="Permalink to &quot;4. [Восстановление сессий](./session-recovery/)&quot;">​</a></h3><p>Узнайте о механизмах восстановления сессий для автоматической обработки сбоев вызовов инструментов и прерываний.</p><ul><li>Автоматическая обработка ошибок tool_result_missing</li><li>Исправление проблем thinking_block_order</li><li>Настройка параметров auto_resume и session_recovery</li></ul><h3 id="_5-механизм-преобразования-запросов" tabindex="-1">5. <a href="./request-transformation/">Механизм преобразования запросов</a> <a class="header-anchor" href="#_5-механизм-преобразования-запросов" aria-label="Permalink to &quot;5. [Механизм преобразования запросов](./request-transformation/)&quot;">​</a></h3><p>Углубленно поймите механизм преобразования запросов и то, как он обеспечивает совместимость с различными протоколами AI-моделей.</p><ul><li>Поймите различия в протоколах моделей Claude и Gemini</li><li>Разбирайте ошибки 400, вызванные несовместимостью схем</li><li>Оптимизируйте конфигурацию Thinking для достижения наилучшей производительности</li></ul><h3 id="_6-руководство-по-конфигурации" tabindex="-1">6. <a href="./configuration-guide/">Руководство по конфигурации</a> <a class="header-anchor" href="#_6-руководство-по-конфигурации" aria-label="Permalink to &quot;6. [Руководство по конфигурации](./configuration-guide/)&quot;">​</a></h3><p>Освойте все параметры конфигурации для настройки поведения плагина по требованию.</p><ul><li>Расположение и приоритет конфигурационных файлов</li><li>Настройки поведения моделей, ротации аккаунтов и поведения приложений</li><li>Рекомендуемые конфигурации для сценариев с одним аккаунтом, несколькими аккаунтами и параллельными агентами</li></ul><h3 id="_7-оптимизация-параллельных-агентов" tabindex="-1">7. <a href="./parallel-agents/">Оптимизация параллельных агентов</a> <a class="header-anchor" href="#_7-оптимизация-параллельных-агентов" aria-label="Permalink to &quot;7. [Оптимизация параллельных агентов](./parallel-agents/)&quot;">​</a></h3><p>Оптимизируйте распределение аккаунтов для сценариев с параллельными агентами и включите смещение PID.</p><ul><li>Поймите проблемы конфликтов аккаунтов в сценариях с параллельными агентами</li><li>Включите смещение PID для приоритизации различных аккаунтов в разных процессах</li><li>Комбинируйте со стратегией round-robin для максимизации использования нескольких аккаунтов</li></ul><h3 id="_8-отладочные-журналы" tabindex="-1">8. <a href="./debug-logging/">Отладочные журналы</a> <a class="header-anchor" href="#_8-отладочные-журналы" aria-label="Permalink to &quot;8. [Отладочные журналы](./debug-logging/)&quot;">​</a></h3><p>Включите отладочные журналы для разбора проблем и мониторинга состояния работы.</p><ul><li>Включите отладочные журналы для записи подробной информации</li><li>Поймите различные уровни журналов и сценарии их применения</li><li>Интерпретируйте содержимое журналов для быстрого определения проблем</li></ul><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения изучения расширенных функций вы можете:</p><ul><li>📖 Обратиться к <a href="./../faq/">Часто задаваемым вопросам</a> для решения проблем, возникших при использовании</li><li>📚 Прочитать <a href="./../appendix/">Приложение</a> для понимания архитектурного дизайна и полного справочника по конфигурации</li><li>🔄 Следить за <a href="./../changelog/">Журналом изменений</a> для получения информации о новых функциях и изменениях</li></ul>',32)])])}const _=i(r,[["render",o]]);export{p as __pageData,_ as default};
